#include <charconv>
#include <string_view>
#include <iostream>
#include <chrono>
#include <vector>

class FastLogger {
    char buffer[1024];
    char* current;

public:
    FastLogger() : current(buffer) {}

    void reset() { current = buffer; }

    void add(std::string_view str) {
        size_t len = str.size();
        std::copy(str.begin(), str.end(), current);
        current += len;
    }

    void add(int value) {
        auto [ptr, ec] = std::to_chars(current, buffer + sizeof(buffer), value);
        if (ec == std::errc{}) {
            current = ptr;
        }
    }

    void add(double value) {
        auto [ptr, ec] = std::to_chars(current, buffer + sizeof(buffer), value);
        if (ec == std::errc{}) {
            current = ptr;
        }
    }

    std::string_view get_log() const {
        return std::string_view(buffer, current - buffer);
    }

    void flush() {
        std::cout << get_log();
        reset();
    }
};

struct SensorReading {
    std::string name;
    double value;
    int timestamp;
};

int main() {
    std::vector<SensorReading> readings = {
        {"LIDAR", 12.456, 1000},
        {"Camera", 30.123, 1001},
        {"RADAR", 45.678, 1002},
        {"GPS", 100.234, 1003}
    };

    FastLogger logger;

    auto start = std::chrono::high_resolution_clock::now();

    for (const auto& reading : readings) {
        logger.add("[");
        logger.add(reading.timestamp);
        logger.add("] ");
        logger.add(reading.name);
        logger.add(": ");
        logger.add(reading.value);
        logger.add("\n");
    }

    auto end = std::chrono::high_resolution_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::microseconds>(end - start);

    logger.flush();
    std::cout << "\nLogging took " << duration.count() << " μs\n";

    return 0;
}

